type Cell = [number, number];

export function nextGeneration(cells: Cell[]): Cell[] {
  const isAlive = (x: number, y: number): boolean =>
    cells.some(([cx, cy]) => cx === x && cy === y);

  const countNeighbors = (x: number, y: number): number => {
    let count = 0;
    for (let dx = -1; dx <= 1; dx++) {
      for (let dy = -1; dy <= 1; dy++) {
        if (dx === 0 && dy === 0) continue;
        if (isAlive(x + dx, y + dy)) count++;
      }
    }
    return count;
  };

  const candidates: Cell[] = [];
  for (const [x, y] of cells) {
    for (let dx = -1; dx <= 1; dx++) {
      for (let dy = -1; dy <= 1; dy++) {
        candidates.push([x + dx, y + dy]);
      }
    }
  }

  const next: Cell[] = [];
  for (const [x, y] of candidates) {
    if (next.some(([nx, ny]) => nx === x && ny === y)) continue;
    const neighbors = countNeighbors(x, y);
    if (isAlive(x, y)) {
      if (neighbors === 2 || neighbors === 3) next.push([x, y]);
    } else {
      if (neighbors === 3) next.push([x, y]);
    }
  }
  return next;
}

